import { Link } from 'react-router-dom'
import { Star, Heart, ShoppingCart } from 'lucide-react'
import type { Product } from '@/data/products'
import { Badge } from '@/components/ui/badge'
import { Button } from '@/components/ui/button'
import { cn } from '@/lib/utils'
import useWishlistStore from '@/stores/useWishlistStore'
import useCartStore from '@/stores/useCartStore'
import { useToast } from '@/hooks/use-toast'

interface ProductCardProps {
  product: Product
  className?: string
}

export default function ProductCard({ product, className }: ProductCardProps) {
  const { hasItem, toggleItem } = useWishlistStore()
  const { addItem, setCartOpen } = useCartStore()
  const { toast } = useToast()
  const isFavorited = hasItem(product.id)

  const handleFavorite = (e: React.MouseEvent) => {
    e.preventDefault()
    e.stopPropagation()
    toggleItem(product.id)
  }

  const handleAddToCart = (e: React.MouseEvent) => {
    e.preventDefault()
    e.stopPropagation()
    addItem(product)
    setCartOpen(true)
    toast({
      title: 'Adicionado ao carrinho',
      description: `${product.title} foi adicionado ao seu carrinho.`,
    })
  }

  return (
    <Link to={`/product/${product.id}`} className={cn('group flex flex-col', className)}>
      <div className="relative aspect-[4/5] overflow-hidden rounded-lg mb-3 bg-muted isolate">
        <img
          src={product.images[0]}
          alt={product.title}
          className={cn(
            'absolute inset-0 w-full h-full object-cover transition-opacity duration-500 ease-in-out',
            product.images.length > 1 ? 'group-hover:opacity-0' : '',
          )}
        />
        {product.images.length > 1 && (
          <img
            src={product.images[1]}
            alt={`${product.title} - Vista Alternativa`}
            className="absolute inset-0 w-full h-full object-cover opacity-0 transition-opacity duration-500 ease-in-out group-hover:opacity-100"
          />
        )}

        <div className="absolute inset-0 bg-black/5 opacity-0 group-hover:opacity-100 transition-opacity duration-300 pointer-events-none" />

        <div className="absolute top-2 left-2 flex flex-col gap-1.5 z-10">
          {product.isNew && (
            <Badge className="bg-white text-black hover:bg-white/90 shadow-sm border-none rounded-sm px-2 py-0.5 text-[10px] font-bold uppercase tracking-wider">
              Novo
            </Badge>
          )}
          {product.isBestSeller && (
            <Badge className="bg-primary text-primary-foreground hover:bg-primary/90 shadow-sm border-none rounded-sm px-2 py-0.5 text-[10px] font-bold uppercase tracking-wider">
              Mais Vendido
            </Badge>
          )}
        </div>

        <button
          onClick={handleFavorite}
          className="absolute top-2 right-2 z-20 p-2 rounded-full bg-background/50 backdrop-blur-md hover:bg-background/90 transition-all border border-transparent hover:border-border shadow-sm group/btn"
          aria-label={isFavorited ? 'Remover dos favoritos' : 'Adicionar aos favoritos'}
        >
          <Heart
            className={cn(
              'w-4 h-4 transition-colors',
              isFavorited
                ? 'fill-red-500 text-red-500'
                : 'text-foreground group-hover/btn:text-red-500',
            )}
          />
        </button>
      </div>

      <div className="flex flex-col flex-1">
        <h3 className="text-sm font-medium leading-tight text-foreground line-clamp-2 mb-1 group-hover:underline decoration-muted-foreground/30 underline-offset-2">
          {product.title}
        </h3>

        <div className="flex items-center text-xs text-muted-foreground mb-1">
          <div className="flex items-center font-medium text-foreground">
            {product.rating}
            <Star className="w-3.5 h-3.5 ml-1 fill-foreground" />
          </div>
          <span className="mx-2 opacity-50">•</span>
          <span className="truncate">{product.category}</span>
        </div>

        <div className="mt-1 flex items-center justify-between gap-2">
          <span className="font-bold text-sm sm:text-base text-foreground shrink-0">
            R$ {product.price.toFixed(2).replace('.', ',')}
          </span>
          <Button
            size="sm"
            className="h-8 px-2 sm:px-3 text-[10px] sm:text-xs shrink-0"
            onClick={handleAddToCart}
            title="Adicionar ao carrinho"
          >
            <ShoppingCart className="w-3 h-3 mr-1 sm:w-3.5 sm:h-3.5 sm:mr-1.5" />
            <span className="hidden sm:inline">Adicionar ao carrinho</span>
            <span className="sm:hidden">Adicionar</span>
          </Button>
        </div>
      </div>
    </Link>
  )
}
